{
  "shots": [
    {
      "shot_id": "SH03",
      "priority": "P1",
      "intent": "让樱子在离开前回望雾中的银座方向，用一句低声提问外化她对母亲旧世界的牵挂，并把回应空间交给下一镜的美咲。",
      "duration_sec": 5,
      "shot_type": "双人近景含远景背景",
      "movement": "固定机位，允许极轻微稳定推镜",
      "framing_focus": "首帧定格在东京站新干线清晨站台靠近检票口处，樱子正侧脸位于画面中心偏左，回望画面左上方雾中的银座方向都市轮廓，嘴部清楚可见；美咲三分之二侧脸位于画面右侧，闭嘴看着樱子。",
      "action_intent": "本镜头只执行单人对白：樱子停步侧身回望雾中银座方向，仍与美咲轻轻牵手，低声问出一句话；美咲保持沉默、闭嘴静听，不做回应。",
      "emotion_intent": "樱子的稚嫩不安与不舍可见，美咲以安静注视承接她的牵挂。",
      "scene_id": "EP21_TOKYO_STATION_PLATFORM_MORNING_GATE",
      "scene_name": "东京站新干线清晨站台靠近检票口处",
      "dialogue": [
        {
          "speaker": "佐藤樱子",
          "text": "姨妈，那边……妈妈的世界，还在等吗？",
          "purpose": "外化樱子对母亲和彩花旧世界的牵挂",
          "source": "onscreen",
          "listener": "佐藤美咲"
        }
      ],
      "narration": [],
      "subtitle": [
        "姨妈，那边……妈妈的世界，还在等吗？"
      ],
      "positive_core": "首帧为单一稳定画面：东京站新干线清晨站台靠近检票口处，樱子位于画面中心偏左，以正侧脸回望画面左上方雾中的银座方向都市轮廓，嘴部清楚可见，美咲位于画面右侧，以三分之二侧脸看着樱子，两人仍轻轻牵手，银灰检票闸机在右后方静止。竖屏9:16，低饱和写实电影感，清晨灰蓝薄雾笼罩远处建筑剪影，站台金属与玻璃反射冷淡晨光。佐藤樱子穿深蓝色中学生水手服套装、白色领巾、及膝百褶裙、白色袜子、黑色学生皮鞋，朴素日常呈现；佐藤美咲穿低饱和浅米色旧丝质过膝礼服，细肩带略松但衣着完整，黑色低跟鞋，头发自然垂落，朴素克制呈现。5秒内只有樱子低声开口，美咲闭嘴静听，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "first_frame_contract": {
        "location": "东京站新干线清晨站台靠近检票口处",
        "visual_center": "樱子正侧脸回望雾中银座方向并准备低声说话的脸部",
        "visible_characters": [
          "佐藤樱子",
          "佐藤美咲"
        ],
        "character_positions": {
          "佐藤樱子": "画面中心偏左，身体微侧向检票口方向，脸以正侧脸朝向画面左上方雾中银座方向，两人相握的手位于画面下缘",
          "佐藤美咲": "画面右侧稍后半步，三分之二侧脸朝向樱子，手仍与樱子相握"
        },
        "character_face_visibility": {
          "佐藤樱子": "脸部可见，正侧脸，可见眼睛、鼻梁和嘴部，嘴部无遮挡，是本镜头唯一主动说话人",
          "佐藤美咲": "脸部可见，三分之二侧脸，可见五官和眼神，嘴部闭合，保持沉默"
        },
        "key_props": [
          "GINZA_FOGGY_SKYLINE_VIEW",
          "TICKET_GATE_ROW"
        ],
        "speaking_state": "佐藤樱子正在低声说一句话；佐藤美咲沉默、闭嘴、无口型；无电话远端声音",
        "camera_motion_allowed": "固定机位，允许极轻微稳定推镜"
      },
      "dialogue_blocking": {
        "active_speaker": "佐藤樱子",
        "first_speaker": "佐藤樱子",
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [
          "佐藤美咲"
        ],
        "lip_sync_policy": "single_active_speaker"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "medium",
        "risk_notes": "两名角色同框且只有樱子说话，需保持樱子脸部为视觉中心、嘴部清楚可见；美咲全程闭嘴无口型，动作仅限静听和微小眼神反应。",
        "prop_library": {
          "GINZA_FOGGY_SKYLINE_VIEW": {
            "display_name": "雾中的银座方向都市轮廓",
            "count": "1片远处城市轮廓背景",
            "size": "占竖屏画面上半部约三分之一高度",
            "color": "低饱和灰蓝色雾气中透出暗灰建筑剪影",
            "material": "远景城市建筑与晨雾视觉层",
            "structure": "多栋高低错落建筑的模糊剪影",
            "front_description": "none",
            "back_description": "none",
            "canonical_motion_policy": "作为背景静止；列车启动后通过车窗相对后退"
          },
          "TICKET_GATE_ROW": {
            "display_name": "新干线检票闸机",
            "count": "1台主闸机",
            "size": "长约1.8米，宽约0.28米，高约1.05米",
            "color": "银灰金属机身，黑色感应面，透明浅灰挡板",
            "material": "拉丝金属、黑色硬塑料、透明亚克力",
            "structure": "长方体机身，两侧感应区，中间双片透明挡板",
            "front_description": "none",
            "back_description": "none",
            "canonical_motion_policy": "固定在地面，只有透明挡板可在通过时向两侧打开一次"
          }
        },
        "prop_contract": [
          {
            "prop_id": "GINZA_FOGGY_SKYLINE_VIEW",
            "position": "首帧画面左上方远景，位于清晨灰蓝薄雾中，作为樱子视线投向的方向",
            "first_frame_visible": true,
            "motion_policy": "本镜头作为远景背景保持静止，不移动、不变形",
            "controlled_by": "none",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "仅保留1片远处城市轮廓背景，不新增同类背景副本",
            "flip_policy": "none"
          },
          {
            "prop_id": "TICKET_GATE_ROW",
            "position": "首帧画面右后方靠近站台通道，银灰金属机身和透明浅灰挡板可见",
            "first_frame_visible": true,
            "motion_policy": "本镜头固定在地面，透明挡板保持闭合，不打开",
            "controlled_by": "none",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "仅保留1台主闸机，不新增闸机数量",
            "flip_policy": "none"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "none",
          "screen_content_visible": false
        }
      },
      "source_basis": "“樱子脚步顿了顿，目光投向身后，银座方向的都市轮廓在雾中模糊。她低语：‘姨妈，那边……妈妈的世界，还在等吗？’”"
    }
  ],
  "qa_report": [
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "只生成SH03一个镜头；镜头任务为dialogue；只有佐藤樱子一个onscreen主动说话人，美咲沉默无口型。"
    },
    {
      "check": "first frame stability and face visibility",
      "result": "pass",
      "notes": "首帧为东京站新干线清晨站台单一稳定地点；樱子正侧脸、美咲三分之二侧脸均可见，樱子嘴部清楚可见。"
    },
    {
      "check": "continuity with SH02",
      "result": "pass",
      "notes": "继承上一镜的同一站台位置、靠近检票口状态和两人相握的手；本镜不重复上一镜手部细节功能，转为樱子对白提问。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "使用并定义GINZA_FOGGY_SKYLINE_VIEW与TICKET_GATE_ROW，尺寸、颜色、材质、结构和运动策略沿用道具目录；未新增不定量道具。"
    },
    {
      "check": "costume and safety wording",
      "result": "pass",
      "notes": "樱子服装遵守本集服装契约；美咲服装继承前序镜头并保持同一集连续性；使用人物衣着完整、保持日常社交距离、朴素克制呈现。"
    },
    {
      "check": "phone handling",
      "result": "pass",
      "notes": "本镜无电话通话、无手机道具、无远端声音。"
    },
    {
      "check": "source traceability",
      "result": "pass",
      "notes": "镜头内容直接对应TARGET_FACTS index 3与TARGET_SPINE_ROW：樱子回望雾中银座方向，并向美咲询问母亲的世界是否还在等待。"
    }
  ]
}
